window.jQuery = window.$ = function(selector){
    return new $.fn.init(selector);
};
$.fn = $.prototype = {
    init:function(sel){
        this.el = document.querySelectorAll(sel);
        this.length = this.el.length;
        return this;
    },
    // 点击事件
    click:function(cb){
        for(let i=0;i<this.length;i++){
            this.el[i].addEventListener('click',cb)
        }
        return this;
    },
    // 获取/设置值
    val:function(v){
        if(v===undefined) return this.el[0].value;
        this.el[0].value = v;
        return this;
    },
    // 表单提交
    submit:function(cb){
        for(let i=0;i<this.length;i++){
            this.el[i].addEventListener('submit',e=>{
                e.preventDefault();cb()
            })
        }
        return this;
    },
    // 显示隐藏
    show:function(){this.css('display','block')},
    hide:function(){this.css('display','none')},
    css:function(k,v){
        for(let i=0;i<this.length;i++) this.el[i].style[k]=v;
        return this;
    }
};
$.fn.init.prototype = $.fn;
// 页面就绪
$.ready = function(cb){
    if(document.readyState=="loading"){
        document.addEventListener('DOMContentLoaded',cb)
    }else cb();
}